 13	// rgb in [0,255] bounds
 14	type Color = { r: number; g: number; b: number };
 15	type ColorMap = Color[];
 16	
 17	const criticalColorMap: ColorMap = [
 18	  { r: 250, g: 234, b: 232 },
 19	  { r: 163, g: 0, b: 0 },
 20	  { r: 44, g: 0, b: 0 },
 21	  { r: 20, g: 0, b: 20 }
 22	];
 23	
 24	const warningColorMap: ColorMap = [
 25	  { r: 253, g: 247, b: 231 },
 26	  { r: 240, g: 171, b: 0 },
 27	  { r: 236, g: 122, b: 8 },
 28	  { r: 59, g: 31, b: 0 }
 29	];
 30	
 31	const infoColorMap: ColorMap = [
 32	  { r: 62, g: 134, b: 53 },
 33	  { r: 228, g: 245, b: 188 },
 34	  { r: 154, g: 216, b: 216 }
 35	];
 36	
 37	const getCellColors = (value: number, rangeFrom: number, rangeTo: number, colorMap: ColorMap) => {
 38	  // Ensure value is valid and within range
 39	  if (!isFinite(value) || isNaN(value)) {
 40	    value = rangeFrom;
 41	  }
 42	
 43	  const clamped = Math.max(rangeFrom, Math.min(rangeTo, value));
 44	  const ratio = (clamped - rangeFrom) / (rangeTo - rangeFrom); // e.g. 0.8 | 0 | 1
 45	  const colorRatio = ratio * (colorMap.length - 1); // e.g. (length is 3) 1.6 | 0 | 2
 46	
 47	  // Ensure indices are within bounds
 48	  const lowIndex = Math.min(Math.max(0, Math.floor(colorRatio)), colorMap.length - 1);
 49	  const highIndex = Math.min(Math.max(0, Math.ceil(colorRatio)), colorMap.length - 1);
 50	
 51	  const colorLow = colorMap[lowIndex];
 52	  const colorHigh = colorMap[highIndex];
 53	  const remains = colorRatio - Math.floor(colorRatio); // e.g. 0.6 | 0 | 0
 54	
 55	  const r = Math.floor((colorHigh.r - colorLow.r) * remains + colorLow.r);
 56	  const g = Math.floor((colorHigh.g - colorLow.g) * remains + colorLow.g);
 57	  const b = Math.floor((colorHigh.b - colorLow.b) * remains + colorLow.b);
 58	  const brightness = 0.21 * r + 0.72 * g + 0.07 * b; // https://www.johndcook.com/blog/2009/08/24/algorithms-convert-color-grayscale/
 59	  const textColor = brightness > 128 ? 'var(--pf-global--palette--black-1000)' : 'var(--pf-global--palette--black-100)';
 60	  return {
 61	    color: textColor,
 62	    backgroundColor: `rgb(${r},${g},${b})`
 63	  };
 64	};
 65	
 66	const buildGradientCSS = (colorMap: ColorMap): string => {
 67	  const colorStops = colorMap.map(c => `rgb(${c.r},${c.g},${c.b})`);
 68	  return 'linear-gradient(to right,' + colorStops.join(',') + ')';
 69	};
 70	
 71	export const HealthColorSquare: React.FC<HealthColorSquareProps> = ({ item }) => {
 72	  const { t } = useTranslation('plugin__netobserv-plugin');
 73	
 74	  const scoreData = React.useMemo(() => {
 75	    const scoreForMap = computeExcessRatioStatusWeighted(item);
 76	    const score = computeHealthItemScore(item);
 77	    return {
 78	      severity: item.severity,
 79	      scoreForMap,
 80	      rawScore: score.rawScore,
 81	      weight: score.weight
 82	    };
 83	  }, [item]);
 84	
 85	  if (!scoreData || !scoreData.severity) {
 86	    return null;
 87	  }
 88	
 89	  const { severity, scoreForMap, rawScore, weight } = scoreData;
 90	
 91	  const colorMap = severity === 'critical' ? criticalColorMap : severity === 'warning' ? warningColorMap : infoColorMap;
 92	
 93	  return (
 94	    <Tooltip
 95	      content={
 96	        <>
 97	          {t('Score') + ': ' + valueFormat(rawScore)}
 98	          <br />
 99	          {t('Weight') + ': ' + weight}
100	          <br />
101	          <div className="gradient" style={{ backgroundImage: buildGradientCSS(colorMap) }}>
102	            <span className="vertical-mark" style={{ width: 100 * scoreForMap + '%' }} />
103	          </div>
104	        </>
105	      }
106	    >
107	      <div className={'cell'} style={getCellColors(scoreForMap, 0, 1, colorMap)} />
108	    </Tooltip>
109	  );
110	};

