  1	import { PrometheusLabels } from '@openshift-console/dynamic-plugin-sdk';
  2	import {
  3	  AlertState,
  4	  buildStats,
  5	  computeHealthItemScore,
  6	  computeResourceScore,
  7	  HealthItem,
  8	  HealthStat,
  9	  Severity
 10	} from '../health-helper';
 11	
 12	const mockAlert = (
 13	  name: string,
 14	  severity: string,
 15	  state: string,
 16	  threshold: number,
 17	  value: number,
 18	  labels?: PrometheusLabels
 19	): HealthItem => {
 20	  const item: HealthItem = {
 21	    ruleName: name,
 22	    labels: { alertname: name, severity: severity, ...labels },
 23	    severity: severity as Severity,
 24	    state: state as AlertState,
 25	    ruleID: '',
 26	    description: '',
 27	    summary: '',
 28	    threshold: '',
 29	    thresholdF: threshold,
 30	    upperBound: '',
 31	    metadata: {
 32	      alertThresholdF: threshold,
 33	      alertThreshold: '',
 34	      upperBoundF: 100,
 35	      upperBound: '',
 36	      unit: '%',
 37	      links: []
 38	    },
 39	    value: value
 40	  };
 41	  if (labels?.namespace) {
 42	    item.metadata.namespaceLabels = ['namespace'];
 43	  }
 44	  if (labels?.node) {
 45	    item.metadata.nodeLabels = ['node'];
 46	  }
 47	  if (labels?.workload) {
 48	    item.metadata.workloadLabels = ['workload'];
 49	  }
 50	  if (labels?.kind) {
 51	    item.metadata.kindLabels = ['kind'];
 52	  }
 53	  return item;
 54	};
 55	
 56	describe('health helpers, score', () => {
 57	  it('should compute unweighted alert min score', () => {
 58	    const alert = mockAlert('test', 'critical', 'firing', 10, 10);
 59	    const score = computeHealthItemScore(alert);
 60	    expect(score.rawScore).toBeCloseTo(6.0, 2);
 61	    expect(score.weight).toEqual(1);
 62	  });
 63	
 64	  it('should compute unweighted alert max score', () => {
 65	    const alert = mockAlert('test', 'critical', 'firing', 10, 100);
 66	    const score = computeHealthItemScore(alert);
 67	    expect(score.rawScore).toEqual(0);
 68	    expect(score.weight).toEqual(1);
 69	  });
 70	
 71	  it('should compute weighted alert score', () => {
 72	    const alert = mockAlert('test', 'info', 'pending', 10, 10);
 73	    const score = computeHealthItemScore(alert);
 74	    expect(score.rawScore).toBeCloseTo(10.0, 2);
 75	    expect(score.weight).toEqual(0.075);
 76	  });
 77	
 78	  it('should compute unweighted alert score with upper bound', () => {
 79	    const alert = mockAlert('test', 'critical', 'firing', 100, 500);
 80	    alert.metadata!.upperBoundF = 1000;
 81	    const score = computeHealthItemScore(alert);
 82	    expect(score.rawScore).toBeCloseTo(3.33, 2);
 83	  });
 84	
 85	  it('should compute unweighted alert score with clamping', () => {
 86	    // below threshold
 87	    const alert = mockAlert('test', 'critical', 'firing', 100, 1);
 88	    alert.metadata!.upperBoundF = 1000;
 89	    let score = computeHealthItemScore(alert);
 90	    expect(score.rawScore).toEqual(6);
 91	
 92	    // above upper bound
 93	    alert.value = 5000;
 94	    score = computeHealthItemScore(alert);
 95	    expect(score.rawScore).toEqual(0);
 96	  });
 97	
 98	  it('should compute full score', () => {
 99	    // Start with an empty one => max score
100	    const r: HealthStat = {
101	      name: 'test',
102	      critical: { firing: [], pending: [], silenced: [], inactive: [], recording: [] },
103	      warning: { firing: [], pending: [], silenced: [], inactive: [], recording: [] },
104	      other: { firing: [], pending: [], silenced: [], inactive: [], recording: [] },
105	      score: 0
106	    };
107	    expect(computeResourceScore(r)).toEqual(10);
108	
109	    // Add 3 inactive alerts => still max score
110	    r.critical.inactive.push('test-critical');
111	    r.warning.inactive.push('test-warning');
112	    r.other.inactive.push('test-info');
113	    expect(computeResourceScore(r)).toEqual(10);
114	
115	    // Turn the inactive info into pending => slightly decreasing score
116	    r.other.inactive = [];
117	    r.other.pending = [mockAlert('test-info', 'info', 'pending', 10, 20)];
118	    expect(computeResourceScore(r)).toBeCloseTo(9.98, 2);
119	
120	    // Turn the inactive warning into firing => more decreasing score
121	    r.warning.inactive = [];
122	    r.warning.firing = [mockAlert('test-warning', 'warning', 'firing', 10, 40)];
123	    expect(computeResourceScore(r)).toBeCloseTo(8.92, 2);
124	
125	    // Turn the inactive critical into firing => more decrease
126	    r.critical.inactive = [];
127	    r.critical.firing = [mockAlert('test-critical', 'critical', 'firing', 10, 40)];
128	    expect(computeResourceScore(r)).toBeCloseTo(5.11, 2);
129	  });
130	});
131	
132	describe('health helpers, grouping', () => {
133	  it('should group', () => {
134	    const a1 = mockAlert('test1', 'info', 'pending', 15, 10, { namespace: 'a' });
135	    const a2 = mockAlert('test2', 'warning', 'firing', 20, 30, { namespace: 'a' });
136	    const b = mockAlert('test2', 'warning', 'firing', 20, 30, { namespace: 'b' });
137	    const w = mockAlert('test3', 'warning', 'firing', 20, 30, { namespace: 'a', workload: 'w', kind: 'k' });
138	    const g = mockAlert('test4', 'warning', 'firing', 20, 30, {});
139	
140	    const s = buildStats([a1, a2, b, w, g]);
141	    expect(s.global.score).toBeCloseTo(7.5, 2);
142	    expect(s.global.warning.firing.length).toEqual(1);
143	    expect(s.byNamespace.length).toEqual(2);
144	    expect(s.byNamespace[0].name).toEqual('b');
145	    expect(s.byNamespace[0].score).toBeCloseTo(7.5, 2);
146	    expect(s.byNamespace[0].warning.firing.length).toEqual(1);
147	    expect(s.byNamespace[1].name).toEqual('a');
148	    expect(s.byNamespace[1].score).toBeCloseTo(7.8, 1);
149	    expect(s.byNamespace[1].other.pending.length).toEqual(1);
150	    expect(s.byNamespace[1].warning.firing.length).toEqual(1);
151	    expect(s.byNode).toEqual([]);
152	    expect(s.byOwner.length).toEqual(1);
153	    expect(s.byOwner[0].name).toEqual('w');
154	    expect(s.byOwner[0].score).toBeCloseTo(7.5, 2);
155	    expect(s.byOwner[0].warning.firing.length).toEqual(1);
156	  });
157	});

